class Solution {
public:
    vector<int> evenOddBit(int n) {
        int even = 0;
        int odd = 0;
        int i = 0;
        while (n > 0) {
            if (n & 1) {
                if (i % 2 == 0) {
                    even++;
                } else {
                    odd++;
                }
            }
            i++;
            n >>= 1;
        }
        return {even, odd};
    }
};
```
